-- Security Fix: Replace subquery patterns with security definer functions
-- This addresses two critical security findings:
-- 1. user_auth_sensitive_mfa_exposure
-- 2. users_table_public_exposure

-- Create security definer function to get user's internal ID from auth
CREATE OR REPLACE FUNCTION public.get_user_id_from_auth()
RETURNS uuid
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT id FROM users WHERE auth_user_id = auth.uid() LIMIT 1;
$$;

-- from 20251110173503_84a0a7c2-1bdd-40d3-b911-94a4f05dded2.sql
-- Create security definer function to check if user is in same practice
CREATE OR REPLACE FUNCTION public.is_in_same_practice(_user_id uuid, _target_user_id uuid)
RETURNS boolean
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT EXISTS (
    SELECT 1 
    FROM users u1
    JOIN users u2 ON u1.practice_id = u2.practice_id
    WHERE u1.id = _user_id 
      AND u2.id = _target_user_id
  );
$$;

-- from 20251110174829_141b62e4-58f2-41ce-aad9-f28f9b8221d2.sql
-- CRITICAL FIX 3: Audit MFA access
-- Create audit trigger to log when MFA data is accessed
CREATE OR REPLACE FUNCTION public.audit_mfa_access()
RETURNS TRIGGER AS $$
BEGIN
  -- Log when someone accesses MFA data (not their own)
  IF NOT (NEW.user_id = get_user_id_from_auth()) THEN
    INSERT INTO audit_logs (
      practice_id,
      user_id,
      entity_type,
      entity_id,
      action,
      after_data
    ) VALUES (
      (SELECT practice_id FROM users WHERE id = NEW.user_id),
      get_user_id_from_auth(),
      'mfa_access',
      NEW.user_id,
      TG_OP,
      jsonb_build_object(
        'accessed_user_id', NEW.user_id,
        'has_mfa_enabled', (NEW.mfa_secret IS NOT NULL),
        'timestamp', now()
      )
    );
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path = public;

-- from 20251110174829_141b62e4-58f2-41ce-aad9-f28f9b8221d2.sql
CREATE TRIGGER audit_mfa_sensitive_access
AFTER INSERT OR UPDATE ON user_auth_sensitive
FOR EACH ROW
EXECUTE FUNCTION audit_mfa_access();

