-- Helper function: Get current user's practice_id
CREATE OR REPLACE FUNCTION public.current_practice_id()
RETURNS uuid
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT u.practice_id FROM public.users u WHERE u.auth_user_id = auth.uid()
$$;

-- from 20251219141327_23f138c0-27c6-419e-a368-89108695777a.sql
-- Helper function: Check if current user has a specific capability
CREATE OR REPLACE FUNCTION public.has_capability(cap public.capability, p_id uuid DEFAULT NULL)
RETURNS boolean
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.user_practice_roles upr
    JOIN public.practice_roles pr ON pr.id = upr.practice_role_id
    JOIN public.role_catalog rc ON rc.id = pr.role_catalog_id
    LEFT JOIN public.practice_role_capabilities prc ON prc.practice_role_id = pr.id AND prc.capability = cap
    WHERE upr.user_id = (SELECT id FROM public.users WHERE auth_user_id = auth.uid())
      AND pr.practice_id = COALESCE(p_id, public.current_practice_id())
      AND pr.is_active = true
      AND (prc.capability IS NOT NULL OR cap = ANY(rc.default_capabilities))
  );
$$;

-- from 20251219141327_23f138c0-27c6-419e-a368-89108695777a.sql
-- Helper function: Get all capabilities for current user
CREATE OR REPLACE FUNCTION public.get_user_capabilities(p_id uuid DEFAULT NULL)
RETURNS public.capability[]
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT ARRAY_AGG(DISTINCT cap)
  FROM (
    SELECT unnest(rc.default_capabilities) AS cap
    FROM public.user_practice_roles upr
    JOIN public.practice_roles pr ON pr.id = upr.practice_role_id
    JOIN public.role_catalog rc ON rc.id = pr.role_catalog_id
    WHERE upr.user_id = (SELECT id FROM public.users WHERE auth_user_id = auth.uid())
      AND pr.practice_id = COALESCE(p_id, public.current_practice_id())
      AND pr.is_active = true
    UNION
    SELECT prc.capability
    FROM public.user_practice_roles upr
    JOIN public.practice_roles pr ON pr.id = upr.practice_role_id
    JOIN public.practice_role_capabilities prc ON prc.practice_role_id = pr.id
    WHERE upr.user_id = (SELECT id FROM public.users WHERE auth_user_id = auth.uid())
      AND pr.practice_id = COALESCE(p_id, public.current_practice_id())
      AND pr.is_active = true
  ) sub;
$$;

-- from 20251219154052_bc07e305-7902-4419-9ff7-2d8485118ee8.sql
-- Create has_capability function that checks user capabilities through new role system
-- with fallback to is_practice_manager for backward compatibility
CREATE OR REPLACE FUNCTION public.has_capability(_user_id uuid, _capability capability)
RETURNS boolean
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT 
    -- Fallback: is_practice_manager flag grants all capabilities (temporary)
    EXISTS (
      SELECT 1 FROM users 
      WHERE auth_user_id = _user_id 
      AND is_practice_manager = true
    )
    OR
    -- Master users have all capabilities
    EXISTS (
      SELECT 1 FROM users 
      WHERE auth_user_id = _user_id 
      AND is_master_user = true
    )
    OR
    -- Check role_catalog default_capabilities
    EXISTS (
      SELECT 1
      FROM user_practice_roles upr
      JOIN users u ON u.id = upr.user_id
      JOIN practice_roles pr ON pr.id = upr.practice_role_id
      JOIN role_catalog rc ON rc.id = pr.role_catalog_id
      WHERE u.auth_user_id = _user_id
        AND pr.is_active = true
        AND _capability = ANY(rc.default_capabilities)
    )
    OR
    -- Check practice_role_capabilities overrides
    EXISTS (
      SELECT 1
      FROM user_practice_roles upr
      JOIN users u ON u.id = upr.user_id
      JOIN practice_roles pr ON pr.id = upr.practice_role_id
      JOIN practice_role_capabilities prc ON prc.practice_role_id = pr.id
      WHERE u.auth_user_id = _user_id
        AND pr.is_active = true
        AND prc.capability = _capability
    )
$$;

-- from 20251219154052_bc07e305-7902-4419-9ff7-2d8485118ee8.sql
-- Convenience function for current authenticated user
CREATE OR REPLACE FUNCTION public.current_user_has_capability(_capability capability)
RETURNS boolean
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT public.has_capability(auth.uid(), _capability)
$$;

-- from 20251219154052_bc07e305-7902-4419-9ff7-2d8485118ee8.sql
-- Practice-scoped capability check for multi-practice scenarios
CREATE OR REPLACE FUNCTION public.has_capability_for_practice(
  _user_id uuid, 
  _capability capability, 
  _practice_id uuid
)
RETURNS boolean
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT 
    -- Fallback: is_practice_manager for the same practice
    EXISTS (
      SELECT 1 FROM users 
      WHERE auth_user_id = _user_id 
      AND practice_id = _practice_id
      AND is_practice_manager = true
    )
    OR
    -- Master users have all capabilities
    EXISTS (
      SELECT 1 FROM users 
      WHERE auth_user_id = _user_id 
      AND is_master_user = true
    )
    OR
    -- Role-based capability for specific practice
    EXISTS (
      SELECT 1
      FROM user_practice_roles upr
      JOIN users u ON u.id = upr.user_id
      JOIN practice_roles pr ON pr.id = upr.practice_role_id
      JOIN role_catalog rc ON rc.id = pr.role_catalog_id
      WHERE u.auth_user_id = _user_id
        AND pr.practice_id = _practice_id
        AND pr.is_active = true
        AND _capability = ANY(rc.default_capabilities)
    )
    OR
    -- Override capabilities for specific practice
    EXISTS (
      SELECT 1
      FROM user_practice_roles upr
      JOIN users u ON u.id = upr.user_id
      JOIN practice_roles pr ON pr.id = upr.practice_role_id
      JOIN practice_role_capabilities prc ON prc.practice_role_id = pr.id
      WHERE u.auth_user_id = _user_id
        AND pr.practice_id = _practice_id
        AND pr.is_active = true
        AND prc.capability = _capability
    )
$$;

